module top_module(
    sel,
    in0,
    in1,
    in2,
    in3,
    out
);// Module ports
    input [1:0] sel;
    input in0, in1, in2, in3;
    output out;

    // Local signals
    reg invalid_mux_output;

    // Implement the multiplexer using an always block
    always @ (sel, in0, in1, in2, in3) begin
        case (sel)
            2'b00: invalid_mux_output = in0;
            2'b01: invalid_mux_output = in1;
            2'b10: invalid_mux_output = in2;
            2'b11: invalid_mux_output = in3;
        endcase
    end

    // Assign the output signal to the selected input signal
    assign out = invalid_mux_output;

endmodule
